VALUES
  ('judicial-57112235-moex-00497', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '有關應考試權，下列敘述何者錯誤？', '["應考試權，係指具備一定資格之人民有報考國家所舉辦公務人員任用資格暨專門職業及技術人員執業資 格考試之權利", "依考試法舉行之考試，對於應考資格體格試驗，或檢覈經決定不及格者，得依法提起救濟", "因資格不符而遭否准參選之公職候選人，因選舉於訴訟期間已舉行完畢，已無救濟實益，故法院應裁定 駁回起訴", "受緩刑宣告者，緩刑期間不得參加公務員考試"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00498', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '關於憲法第21條規定之國民教育，下列敘述何者錯誤？', '["本條係規定人民有請求接受國民教育的權利", "國家依本條規定可制定法律強制人民接受國民義務教育", "人民受國民教育以外其他教育之受教權亦可從本條導出", "國民義務教育之內容得由法律形成之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00499', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '依司法院釋字第689號解釋意旨，社會秩序維護法對新聞採訪者之跟追行為有一定的限制，旨在衡平跟追 者的新聞採訪自由與被跟追者之何種自由？', '["結社自由", "言論自由", "遷徙自由", "一般行為自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00500', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '下列何者最不屬於比例原則之內涵？', '["基本權干預之目的應該具體明確", "基本權干預的手段有助於目的達成", "採取較小侵害的干預手段", "手段所造成之損害應不大於其目的所擬維護之公共利益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00501', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '依司法院大法官解釋意旨，獨立機關之設置是否合憲，應綜合各項因素判斷能否維持一定之民主正當性基 礎，下列何者非屬之？', '["設置之目的係為追求憲法上之公共利益", "所職司之任務具有特殊性，並有正當理由足以證立設置之必要性", "重要事項以聽證程序決定，任務執行績效應透明、公開，以方便公眾監督", "立法院對於獨立機關重要人員之任命享有完全之決定與制衡權限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00502', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋意旨，關於立法委員，下列敘述何者正確？', '["區域立法委員，應依各直轄市、縣市及鄉鎮市人口比例分配，並按應選名額劃分同額選舉區選出", "全國不分區及僑居國外國民之立法委員，依政黨名單選舉之，各政黨當選名單中婦女不得低於二分之一", "總統於立法院解散後所發布之緊急命令，應由新任立法委員於就職後追認之", "立法委員於院內公聽會之發言，對外不負民事上損害賠償責任或受刑事上之訴追，亦不負任何行政責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00503', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '下列人員之資格，何者不須經考試院依法考選銓定之？', '["國民小學教師", "護理師", "記帳士", "地政士"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00504', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '關於司法院大法官，下列敘述何者錯誤？', '["大法官任期8年，不分屆次，個別計算，並不得連任", "大法官須超出黨派以外，獨立行使職權，不受任何干涉", "司法院設大法官若干人，並以其中一人為院長、一人為副院長，由總統提名，經立法院同意任命之", "並為院長、副院長之大法官，不受任期之保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00505', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '下列何者屬於憲法法庭之職權？', '["統一法令解釋", "總統罷免案之審理", "大法庭裁定", "法官彈劾案之審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00506', 'judicial-57112235', 'judicial-57112235-moex-111-3d2b73b6', 'sub-judicial-57112235-06', NULL, 'single_choice', '依司法院釋字第527號解釋及憲法訴訟法規定，有關地方之組織及權限，下列敘述何者錯誤？', '["地方自治團體依法享有自主組織權及對自治事項制定規章並執行之權限", "地方自治團體及其所屬機關之組織，應由地方立法機關依中央主管機關所擬訂之準則制定組織自治條例 規定", "地方機關未依法規所設置之機關及所置人員，地方立法機關得刪除其相關預算、審計機關得依法剔除、 追繳其支出", "地方自治團體對函告無效之內容持不同意見時，一律由地方自治團體直接向憲法法庭聲請判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
